use std::borrow::Cow;

fn process_data(data: &str) -> Cow<str> {
    if should_convert_to_uppercase() {
        Cow::Owned(data.to_uppercase())
    } else {
        Cow::Borrowed(data)
    }
}

fn should_convert_to_uppercase() -> bool {
    true
}

